import java.io.IOException;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class XSSFixedServlet extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String sanitizedInput = sanitizeInput(userInput);
        String output = "<h1>Welcome, " + sanitizedInput + "!</h1>";

        response.getWriter().write(output);
    }

    private String sanitizeInput(String input) {
        // Implement proper input sanitization and encoding here
        // For example, you can use OWASP Java Encoder library or other encoding methods
        return encodeForHTML(input);
    }

    private String encodeForHTML(String input) {
        return input.replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;")
                    .replace("\"", "&quot;")
                    .replace("'", "&#39;");

